/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Helper class for Min Priority Queue
    class MinPriorityQueue {
        constructor() {
            this.heap = [];
        }

        isEmpty() {
            return this.heap.length === 0;
        }

        _parent(i) { return Math.floor((i - 1) / 2); }
        _leftChild(i) { return 2 * i + 1; }
        _rightChild(i) { return 2 * i + 2; }

        _swap(i, j) {
            [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
        }

        _compare(a, b) {
            // Compare based on distance (the first element of the stored array [distance, node])
            return a[0] < b[0];
        }

        enqueue(element) {
            this.heap.push(element);
            this._bubbleUp(this.heap.length - 1);
        }

        dequeue() {
            if (this.isEmpty()) return null;
            if (this.heap.length === 1) return this.heap.pop();

            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this._bubbleDown(0);
            return min;
        }

        _bubbleUp(index) {
            while (index > 0) {
                let parentIndex = this._parent(index);
                if (this._compare(this.heap[index], this.heap[parentIndex])) {
                    this._swap(index, parentIndex);
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }

        _bubbleDown(index) {
            let minIndex = index;
            const lastIndex = this.heap.length - 1;

            while (true) {
                let left = this._leftChild(index);
                let right = this._rightChild(index);

                if (left <= lastIndex && this._compare(this.heap[left], this.heap[minIndex])) {
                    minIndex = left;
                }
                if (right <= lastIndex && this._compare(this.heap[right], this.heap[minIndex])) {
                    minIndex = right;
                }

                if (minIndex !== index) {
                    this._swap(index, minIndex);
                    index = minIndex;
                } else {
                    break;
                }
            }
        }
    }

    const INF = Number.MAX_SAFE_INTEGER;

    // 1. Build Graph Representations
    const adjEmpty = Array(n).fill(0).map(() => []);
    const adjCarry = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        const carryCost = cost * tax;

        // Empty paths
        adjEmpty[u].push({ to: v, weight: cost });
        adjEmpty[v].push({ to: u, weight: cost });

        // Carrying paths
        adjCarry[u].push({ to: v, weight: carryCost });
        adjCarry[v].push({ to: u, weight: carryCost });
    }

    /**
     * Dijkstra's Algorithm implementation
     * @param {Array<Array<{to: number, weight: number}>>} adj The adjacency list for the graph
     * @param {number} startNode The starting node
     * @returns {number[]} Array of shortest distances from startNode
     */
    const dijkstra = (adj, startNode) => {
        const distances = Array(n).fill(INF);
        distances[startNode] = 0;

        // Priority Queue stores [distance, node]
        const pq = new MinPriorityQueue();
        pq.enqueue([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > distances[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.to;
                const weight = edge.weight;

                const newDist = d + weight;

                if (newDist < distances[v]) {
                    distances[v] = newDist;
                    pq.enqueue([newDist, v]);
                }
            }
        }
        return distances;
    };

    // 2. Calculate All-Pairs Shortest Paths

    // D_empty[i][j]: Shortest path from i to j (empty)
    const D_empty = [];
    for (let i = 0; i < n; i++) {
        D_empty[i] = dijkstra(adjEmpty, i);
    }

    // D_carry[j][i]: Shortest path from j to i (carrying)
    // We run Dijkstra from j on G_carry, yielding distances[i] = D_carry(j, i)
    const D_carry = [];
    for (let j = 0; j < n; j++) {
        D_carry[j] = dijkstra(adjCarry, j);
    }

    // 3. Final Calculation
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) { // i is the destination store
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel i -> j -> i
        for (let j = 0; j < n; j++) { // j is the purchasing store

            // Check reachability. If any segment is unreachable, skip.
            const dist_i_to_j_empty = D_empty[i][j];
            const dist_j_to_i_carry = D_carry[j][i];

            if (dist_i_to_j_empty === INF || dist_j_to_i_carry === INF) {
                continue;
            }

            // Total Cost = Travel (i->j, empty) + Price(j) + Travel (j->i, carrying)
            // Since prices[j] is up to 10^9 and path costs up to 10^14, we must ensure safe addition.
            // JS numbers handle up to 2^53 - 1 safely, which is sufficient here.
            const totalCost = dist_i_to_j_empty + prices[j] + dist_j_to_i_carry;

            if (totalCost < minCost) {
                minCost = totalCost;
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

