import java.util.PriorityQueue
import kotlin.math.min

data class Edge(val to: Int, val weight: Long)
data class State(val node: Int, val distance: Long) : Comparable<State> {
    override fun compareTo(other: State): Int {
        return distance.compareTo(other.distance)
    }
}

fun solve(n: Long, prices: Array<Long>, roads: Array<Array<Long>>): Array<Long> {
    val N = n.toInt()
    val INF = Long.MAX_VALUE

    // 1. Build Graph Representations
    // G_empty[u]: List of Edges (v, cost)
    val adjEmpty = Array(N) { mutableListOf<Edge>() }
    // G_carry[u]: List of Edges (v, cost * tax)
    val adjCarry = Array(N) { mutableListOf<Edge>() }

    for (road in roads) {
        val u = road[0].toInt()
        val v = road[1].toInt()
        val cost = road[2]
        val tax = road[3]

        val carryCost = cost * tax

        // Empty paths (bidirectional)
        adjEmpty[u].add(Edge(v, cost))
        adjEmpty[v].add(Edge(u, cost))

        // Carrying paths (bidirectional)
        adjCarry[u].add(Edge(v, carryCost))
        adjCarry[v].add(Edge(u, carryCost))
    }

    /**
     * Dijkstra's Algorithm implementation
     * @param adj The adjacency list for the graph
     * @param startNode The starting node
     * @return Array of shortest distances from startNode
     */
    fun dijkstra(adj: Array<MutableList<Edge>>, startNode: Int): LongArray {
        val distances = LongArray(N) { INF }
        distances[startNode] = 0

        // Priority Queue stores State(node, distance)
        val pq = PriorityQueue<State>()
        pq.add(State(startNode, 0))

        while (pq.isNotEmpty()) {
            val currentState = pq.poll()
            val u = currentState.node
            val d = currentState.distance

            if (d > distances[u]) continue

            for (edge in adj[u]) {
                val v = edge.to
                val weight = edge.weight

                // Check for potential overflow before addition if INF was slightly smaller, 
                // but since we start at 0 and use MAX_VALUE, standard addition should be fine 
                // as long as d is not INF (checked implicitly by d <= distances[u])
                if (distances[u] == INF) continue 

                val newDist = d + weight

                if (newDist < distances[v]) {
                    distances[v] = newDist
                    pq.add(State(v, newDist))
                }
            }
        }
        return distances
    }

    // 2. Calculate All-Pairs Shortest Paths

    // D_empty[i][j]: Shortest path from i to j (empty)
    val D_empty = Array(N) { LongArray(N) }
    for (i in 0 until N) {
        D_empty[i] = dijkstra(adjEmpty, i)
    }

    // D_carry[j][i]: Shortest path from j to i (carrying)
    // Run Dijkstra starting at j on G_carry. Result is dist[i].
    val D_carry = Array(N) { LongArray(N) }
    for (j in 0 until N) {
        val distFromJ = dijkstra(adjCarry, j)
        D_carry[j] = distFromJ
    }

    // 3. Final Calculation
    val ans = LongArray(N)

    for (i in 0 until N) { // i is the destination store
        // Option 1: Buy directly at i
        var minCost = prices[i]

        // Option 2: Travel i -> j -> i
        for (j in 0 until N) { // j is the purchasing store

            // Travel i -> j (empty): D_empty[i][j]
            val dist_i_to_j_empty = D_empty[i][j]

            // Travel j -> i (carrying): D_carry[j][i]
            val dist_j_to_i_carry = D_carry[j][i]

            // Check reachability
            if (dist_i_to_j_empty == INF || dist_j_to_i_carry == INF) {
                continue
            }

            // Total Cost = Travel (i->j, empty) + Price(j) + Travel (j->i, carrying)
            // Since costs are calculated to be < INF, the sum should not overflow Long.MAX_VALUE unless intermediate INF states were incorrectly handled.
            val totalCost = dist_i_to_j_empty + prices[j] + dist_j_to_i_carry

            minCost = min(minCost, totalCost)
        }
        ans[i] = minCost
    }

    return ans
}
